static RK_RES demo_ec_verify_common(const char *name, rk_ec_pub_key_pack *pub_key, int hash_algo,
				    const uint8_t *hash, const uint8_t *sign, uint32_t sign_len)
{
	RK_RES res = RK_CRYPTO_SUCCESS;

	res = rk_crypto_init();
	if (res) {
		printf("rk_crypto_init error %08x\n", res);
		return res;
	}

	res = rk_ec_verify(pub_key, hash_algo, NULL, 0, hash, (uint8_t *)sign, sign_len);
	if (res) {
		if(res != RK_CRYPTO_ERR_NOT_SUPPORTED) {
			printf("rk_ec_verify digest failed %x\n", res);
			goto exit;
		}

		res = RK_CRYPTO_SUCCESS;
		printf("%s rk_ec_verify digest not support.\n", name);
	}

	printf("****************** %-20s test PASS !!! ******************\n",
	       __func__);

exit:
	if (res)
		printf("****************** %-20s test FAIL !!! ******************\n",
		       __func__);

	rk_crypto_deinit();

	return res;
}

static RK_RES demo_ec_verify(void)
{
	rk_ec_pub_key_pack pub_key = TEST_INIT_EC_KEY(P192);

	return demo_ec_verify_common("NIST-P192", &pub_key, RK_ALGO_SHA1, g_ec_P192_hash,
				     g_ec_P192_signature, sizeof(g_ec_P192_signature));
}

static RK_RES demo_sm2_verify(void)
{
	rk_ec_pub_key_pack pub_key = TEST_INIT_EC_KEY(SM2);

	return demo_ec_verify_common("SM2", &pub_key, RK_ALGO_SM3, g_ec_SM2_hash,
				     g_ec_SM2_signature, sizeof(g_ec_SM2_signature));
}

RK_RES demo_ec(void)
{
	RK_RES res;

	res = demo_ec_verify();
	if (res) {
		printf("demo_ec_verify demo failed.\n");
		return res;
	}

	res = demo_sm2_verify();
	if (res) {
		printf("demo_sm2_verify demo failed.\n");
		return res;
	}

	return RK_CRYPTO_SUCCESS;
}
